import React, { useEffect, useRef } from 'react'
import { NavLink } from 'react-router-dom'
import { useSelector, useDispatch } from 'react-redux'
import {
  CContainer,
  CDropdown,
  CDropdownItem,
  CDropdownMenu,
  CDropdownToggle,
  CHeader,
  CHeaderNav,
  CHeaderToggler,
  CNavLink,
  CNavItem,
  useColorModes,
} from '@coreui/react'
import CIcon from '@coreui/icons-react'
import {
  cilContrast,
  cilMenu,
  cilMoon,
  cilSun,
} from '@coreui/icons'

import { AppHeaderDropdown } from './header/index'
import { Languagei18n } from './language/index'
import useAuth from '../hooks/useAuth';

const AppHeader = () => {
  const headerRef = useRef()
  const { user } = useAuth()

  const { colorMode, setColorMode } = useColorModes('coreui-free-react-admin-template-theme')

  const dispatch = useDispatch()
  const sidebarShow = useSelector((state) => state.changeState.sidebarShow)

  useEffect(() => {
    document.addEventListener('scroll', () => {
      headerRef.current &&
        headerRef.current.classList.toggle('shadow-sm', document.documentElement.scrollTop > 0)
    })
  }, [])

  return (
    <>
      {/* Inline style override with !important */}
      <style>
        {`
          .custom-header-bg {
            background-color: #fff !important;
            color: #212529 !important;
            border-bottom: 1px solid #aab3c5 !important;
            z-index: 1020;
          }
        `}
      </style>

      <CHeader
        position="sticky"
        className="mb-4 p-0 custom-header-bg"
        ref={headerRef}
      >
        <CContainer className="border-bottom px-4" fluid>
          <CHeaderToggler
            onClick={() => console.log({ type: 'set', sidebarShow: !sidebarShow })}
            style={{ marginInlineStart: '-14px' }}
          >
            {/* <CIcon icon={cilMenu} size="lg" style={{ color: '#3559E0' }} /> */}
          </CHeaderToggler>

          <CHeaderNav className="d-none d-md-flex">
            <CNavItem>
              <CNavLink component={NavLink}>
                <Languagei18n />
              </CNavLink>
            </CNavItem>
          </CHeaderNav>

          <CHeaderNav className="ms-auto">
            <CNavItem>
              {/* Optional right nav item */}
            </CNavItem>
          </CHeaderNav>

          <CHeaderNav>
            <CDropdown variant="nav-item" placement="bottom-end">
              <CDropdownToggle
                caret={false}
                style={{
                  backgroundColor: 'transparent',
                  border: 'none',
                  color: '#000',
                }}
              >
                {colorMode === 'dark' ? (
                  <CIcon icon={cilMoon} size="lg" style={{ color: '#000' }} />
                ) : colorMode === 'auto' ? (
                  <CIcon icon={cilContrast} size="lg" style={{ color: '#000' }} />
                ) : (
                  <CIcon icon={cilSun} size="lg" style={{ color: '#000' }} />
                )}
              </CDropdownToggle>

              <CDropdownMenu style={{ backgroundColor: '#fff', color: '#000' }}>
                <CDropdownItem
                  active={colorMode === 'light'}
                  className="d-flex align-items-center"
                  component="button"
                  type="button"
                  style={{ color: '#000' }}
                  onClick={() => setColorMode('light')}
                >
                  <CIcon className="me-2" icon={cilSun} size="lg" style={{ color: '#000' }} /> Light
                </CDropdownItem>
                <CDropdownItem
                  active={colorMode === 'dark'}
                  className="d-flex align-items-center"
                  component="button"
                  type="button"
                  style={{ color: '#000' }}
                  onClick={() => setColorMode('dark')}
                >
                  <CIcon className="me-2" icon={cilMoon} size="lg" style={{ color: '#000' }} /> Dark
                </CDropdownItem>
                <CDropdownItem
                  active={colorMode === 'auto'}
                  className="d-flex align-items-center"
                  component="button"
                  type="button"
                  style={{ color: '#000' }}
                  onClick={() => setColorMode('auto')}
                >
                  <CIcon className="me-2" icon={cilContrast} size="lg" style={{ color: '#000' }} /> Auto
                </CDropdownItem>
              </CDropdownMenu>
            </CDropdown>

            <CNavLink href="#" className="d-flex align-items-center" style={{ color: '#212529' }}>
              {user.username} - {user.privilege}
            </CNavLink>
          </CHeaderNav>

          <AppHeaderDropdown />
        </CContainer>
      </CHeader>
    </>
  )
}

export default AppHeader
