import React, { useMemo } from 'react';
import { useSelector, useDispatch } from 'react-redux';
import {
  CCloseButton,
  CSidebar,
  CSidebarBrand,
  CSidebarFooter,
  CSidebarHeader,
  CSidebarNav,
  CSidebarToggler,
} from '@coreui/react';
import CIcon from '@coreui/icons-react';
import SimpleBar from 'simplebar-react';
import 'simplebar-react/dist/simplebar.min.css';
import useAuth from 'src/hooks/useAuth';
import { AppSidebarNav } from './AppSidebarNav';
import Paths from 'src/services/common.settings/config';
import _navAdmin from 'src/navigations/navigationAdmin';
import _navComponenet from 'src/navigations/_navComponenet';
import _navStandard from 'src/navigations/navigation.standard';
import _navSettings from 'src/navigations/navigation.settings';
import i18n from 'src/i18n';
import AppHeader from './AppHeader';

function AppSidebar() {
  const dispatch = useDispatch();
  const { sidebarUnfoldable } = useSelector((state) => state);
  const sidebarShow = useSelector((state) => state.changeState.sidebarShow)
  const { user } = useAuth();

  const navItems = useMemo(() => {
    if (!user) return null;

    if (user.privilege === 'design') {
      return _navComponenet;
    } 
    if (['SUADMIN', 'SUADMINRH'].includes(user.privilege)) {
      return [..._navAdmin, ..._navSettings];
    }
    if (user.privilege === 'StandardUser') {
      return _navStandard;
    }
    return null;
  }, [user]);

  return (
    <CSidebar
      colorScheme="dark"
      position="fixed"
      unfoldable={sidebarUnfoldable}
      visible={sidebarShow}
      onVisibleChange={(visible) => {
        dispatch({ type: 'set', sidebarShow: visible });
      }}
    >
      <CSidebarHeader className="border-bottom">
        <CSidebarBrand to="/" >
          <img src={Paths.appSrcLogo} alt="Logo" height={32} />
          <span
            className="small text-body-secondary"
            style={{ textDecoration: 'none', marginRight: '8px' }}
          >{i18n.t('SISidebarTitle')}</span>
          <CIcon customClassName="sidebar-brand-narrow" icon={"sygnet"} height={32} style={{ color: '#212529' }} />
        </CSidebarBrand>
        <CCloseButton
          className="d-lg-none"
          dark
          onClick={() => dispatch({ type: 'set', sidebarShow: false })}
        />
      </CSidebarHeader>

      <CSidebarNav>
        <SimpleBar>
          {navItems && <AppSidebarNav items={navItems} />}
        </SimpleBar>
      </CSidebarNav>
      
      <AppHeader />

      

      <CSidebarFooter className="border-top d-none d-lg-flex">
        <CSidebarToggler
          onClick={() => dispatch({ type: 'set', sidebarUnfoldable: !sidebarUnfoldable })}
        />
        
        
      </CSidebarFooter>

    </CSidebar>
  );
}

export default React.memo(AppSidebar);
