import React from 'react'
import {
  CAvatar,
  CDropdown,
  CDropdownDivider,
  CDropdownHeader,
  CDropdownItem,
  CDropdownMenu,
  CDropdownToggle,
} from '@coreui/react'
import {
  cilAccountLogout,
  cilLockLocked,
} from '@coreui/icons'
import CIcon from '@coreui/icons-react'

import useAuth  from 'src/hooks/useAuth' // Import your Auth context hook
import { useNavigate } from 'react-router-dom';
import i18n from 'src/i18n';

function AppHeaderDropdown() {
  const { logout } = useAuth();
  const navigate = useNavigate();
  const handleLogout = () => {
    logout();
    navigate('/login');
  };
  return (
    <CDropdown variant="nav" >
      <CDropdownToggle placement="bottom-end" className="py-0 pe-0" caret={false}>
        <CIcon icon={cilAccountLogout} size="lg" className="text-primary" />Logout
      </CDropdownToggle>
      <CDropdownMenu className="pt-0" placement="bottom-end">
        <CDropdownHeader className="bg-body-secondary fw-semibold mb-2">{i18n.t('accountTitle')}</CDropdownHeader>
        <CDropdownDivider />
        <CDropdownItem onClick={handleLogout}>
          <CIcon icon={cilLockLocked} className="me-2" />
          {i18n.t('disconnection')} 
        </CDropdownItem>
      </CDropdownMenu>
    </CDropdown>
  )
}

export default AppHeaderDropdown
