import React from 'react'

const Appointments = React.lazy(() => import('../view.users/appointments/index'))
const Calendar = React.lazy(() => import('../view.users/calendar/index'))
const UserCalendarPlugin = React.lazy(() => import('../view.users/calendar/User.Calendar/index'))
const Dashboard = React.lazy(() => import('../view.users/dashboard/index'))
const Unavailabilities = React.lazy(() => import('../view.users/unavailabilities/index'))

const LazyTest = React.lazy(() => import('../view.configs/tags/Lazy.index.jsx'))  
const LazyWrapper = (Component, props = {}) => (
  <React.Suspense fallback={<div>Loading...</div>}>
    <Component {...props} />
  </React.Suspense>
)



/////////////////////////////////////////////////////////////////////////////////////////////////////////////////////////////////////////////
const routeStandars = [
  { path: '/', exact: true, name: 'Home' },
  { path: '/standard/settings/dashboards', name: 'Dashboard', element: Dashboard },
  { path: '/standard/settings/appointments', name: 'Appointments', element: Appointments },
  { path: '/standard/settings/calendars', name: 'Calendar', element: Calendar },
  { path: '/standard/users/settings/calendars', name: 'UserCalendarPlugin', element: UserCalendarPlugin },
  { path: '/standard/settings/unavailabilities', name: 'Unavailabilities', element: Unavailabilities },

/////////////////////////////////////////////////////////////////////////////////////////////////////////////////////////////////////////////
   {
    path: '/standard/settings/appointment',
    name: 'Appointments',
    element: LazyWrapper(LazyTest, { showCompleted: true }),
  },
  
  
]

export default routeStandars